import React, { useState, useEffect, useRef } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const clayLight = '#E2725B'; 
const softCream = '#FDF5E6'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false); 
  const [isClockedIn, setIsClockedIn] = useState(false);
  const [deliveryMode, setDeliveryMode] = useState('Pickup');
  
  // LOGIC STATES
  const [scheduledDate, setScheduledDate] = useState('');
  const [address, setAddress] = useState('');
  const [deliveryZone, setDeliveryZone] = useState('Ikeja, Lagos');
  const inputRef = useRef();
  const autoCompleteRef = useRef();

  const whatsappNumber = "2349122731172";
  const bankInfo = { bank: "PREMIUMTRUST BANK", account: "0112326977", name: "OLUKOYA OMOTOYOSI" };

  const slides = [
    { title: "EVERY BITE, ALWAYS WORTH IT!", subtitle: "NIGERIA'S FAVORITE GRILLS & SMALL CHOPS.", img: "/images/chops_promo.png", bg: terracotta },
    { title: "AFFORDABLE LUXURY WIGS.", subtitle: "Wigs anyone can afford😊!", img: "/images/wigs_promo.png", bg: "#8B0000" },
    { title: "PREMIUM TASTE, 9JA FLAVOR!", subtitle: "THE PERFECT BALANCE OF GOOD FOOD.", img: "/images/lunch_promo.png", bg: terracotta }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above.", img: "/images/customized.jpg", isCustom: true }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]}
    ]
  };

  useEffect(() => {
    if (window.google) {
      autoCompleteRef.current = new window.google.maps.places.Autocomplete(inputRef.current, {
        componentRestrictions: { country: "ng" },
        fields: ["formatted_address"]
      });
      autoCompleteRef.current.addListener("place_changed", () => {
        const place = autoCompleteRef.current.getPlace();
        setAddress(place.formatted_address);
      });
    }
  }, []);

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => setCart([...cart, item]);
  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  const sendToWhatsApp = () => {
    const itemsList = cart.map(item => `- ${item.name} (₦${item.price})`).join('%0A');
    const orderTime = scheduledDate ? `📅 Scheduled: ${scheduledDate}` : "🚀 Instant Delivery";
    const deliveryInfo = deliveryMode === 'Delivery' ? `📍 Zone: ${deliveryZone}%0A🏠 Address: ${address}` : "🏢 Method: Pickup";

    const message = `Hello Àmí by T!%0A%0A*New Order Request*%0A------------------%0A*Time:* ${orderTime}%0A*Method:* ${deliveryMode}%0A${deliveryInfo}%0A%0A*Items:*%0A${itemsList}%0A%0A*Total:* ₦${total.toLocaleString()}%0A%0A*Bank:* ${bankInfo.bank}%0A*Acct:* ${bankInfo.account}`;
    
    window.open(`https://wa.me/${whatsappNumber}?text=${message}`, '_blank');
  };

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. HEADER */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: '#000', zIndex: 1000, borderBottom: '1px solid #1a1a1a' }}>
        <img src={Logo} alt="Logo" style={{ height: '45px' }} />
        <div style={{ display: 'flex', gap: '20px', fontSize: '1.4rem' }}>
          <span>👤</span>
          <span style={{ position: 'relative' }}>
            🛒 <span style={{ position: 'absolute', top: '-10px', right: '-10px', background: terracotta, borderRadius: '50%', padding: '2px 6px', fontSize: '0.7rem' }}>{cart.length}</span>
          </span>
        </div>
      </header>

      {/* 2. DYNAMIC BANNER */}
      <div style={{ position: 'relative', height: '190px', overflow: 'hidden' }}>
        {slides.map((slide, index) => (
          <div key={index} style={{ position: 'absolute', width: '100%', height: '100%', backgroundColor: slide.bg, display: 'flex', alignItems: 'center', opacity: index === currentSlide ? 1 : 0, transition: 'opacity 0.8s ease-in-out', zIndex: index === currentSlide ? 1 : 0 }}>
            <div style={{ flex: 1.2, paddingLeft: '25px', zIndex: 2 }}>
              <h2 style={{ fontSize: '1.6rem', fontWeight: '900', margin: 0, lineHeight: 1.1 }}>{slide.title}</h2>
              <p style={{ fontSize: '0.75rem', margin: '10px 0 0', fontWeight: '700', opacity: 0.9 }}>{slide.subtitle}</p>
            </div>
            <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <img src={slide.img} style={{ height: '145%', width: 'auto', objectFit: 'contain' }} alt="" />
            </div>
          </div>
        ))}
      </div>

      {/* 3. INFO & TOOLS */}
      <div style={{ padding: '20px' }}>
        <h1 style={{ fontSize: '1.6rem', margin: 0, fontWeight: '800' }}>Àmí by T</h1>
        <div style={{ display: 'flex', alignItems: 'center', color: '#888', marginTop: '10px' }}>
          <span style={{ marginRight: '5px' }}>📍</span>
          <select value={deliveryZone} onChange={(e) => setDeliveryZone(e.target.value)} style={{ background: 'none', border: 'none', color: '#888', fontSize: '0.95rem', fontWeight: '700', cursor: 'pointer' }}>
            <option value="Ikeja, Lagos">Ikeja, Lagos</option>
            <option value="Lekki Phase 1">Lekki Phase 1</option>
            <option value="Victoria Island">Victoria Island</option>
          </select>
        </div>
        <input ref={inputRef} placeholder="Enter exact address (Street/Estate)..." style={{ width: '100%', marginTop: '15px', padding: '12px', borderRadius: '10px', border: '1px solid #333', background: '#111', color: '#fff', fontSize: '0.95rem', boxSizing: 'border-box' }} onChange={(e) => setAddress(e.target.value)} />
        <div style={{ marginTop: '15px', position: 'relative' }}>
           <button style={{ width: '100%', padding: '15px', borderRadius: '12px', border: '1px solid #333', background: '#111', color: '#fff', fontWeight: '700', cursor: 'pointer' }}>
             📅 {scheduledDate ? `Scheduled: ${scheduledDate}` : 'Pre-order / Schedule delivery'}
             <input type="datetime-local" onChange={(e) => setScheduledDate(e.target.value)} style={{ position: 'absolute', opacity: 0, width: '100%', left: 0, top: 0, height: '100%', cursor: 'pointer' }} />
           </button>
        </div>
        <div style={{ display: 'flex', marginTop: '15px', backgroundColor: '#111', borderRadius: '12px', padding: '4px' }}>
          <button onClick={() => setDeliveryMode('Pickup')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', backgroundColor: deliveryMode === 'Pickup' ? '#fff' : 'transparent', color: deliveryMode === 'Pickup' ? '#000' : '#888', fontWeight: '800', cursor: 'pointer' }}>Pickup</button>
          <button onClick={() => setDeliveryMode('Delivery')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', backgroundColor: deliveryMode === 'Delivery' ? '#fff' : 'transparent', color: deliveryMode === 'Delivery' ? '#000' : '#888', fontWeight: '800', cursor: 'pointer' }}>Delivery</button>
        </div>
      </div>

      {/* 4. NAV TABS */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '10px 20px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs'].map((item) => (
          <button key={item} onClick={() => setActiveCategory(item)} style={{ whiteSpace: 'nowrap', padding: '10px 22px', borderRadius: '25px', border: activeCategory === item ? '2px solid #fff' : 'none', backgroundColor: activeCategory === item ? '#000' : 'transparent', color: activeCategory === item ? '#fff' : '#888', fontWeight: '800' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 5. MAIN MENU */}
      <main style={{ paddingBottom: '120px' }}>
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', padding: '20px', borderBottom: '1px solid #1a1a1a', alignItems: 'center' }}>
            <div style={{ flex: 1 }}>
              <h4 style={{ margin: 0, fontWeight: '700' }}>{item.name}</h4>
              <p style={{ color: '#888', fontSize: '0.85rem', margin: '5px 0' }}>{item.desc}</p>
              <div style={{ fontWeight: 'bold', color: gold }}>₦{item.price}</div>
            </div>
            <button onClick={() => item.isCustom ? window.open(`https://wa.me/${whatsappNumber}`) : addToCart(item)} style={{ padding: '10px 18px', borderRadius: '20px', border: 'none', backgroundColor: item.isCustom ? gold : terracotta, color: item.isCustom ? '#000' : '#fff', fontWeight: '900' }}>
              {item.isCustom ? 'BOOK' : 'ADD'}
            </button>
          </div>
        ))}

        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '20px' }}>
            <button onClick={() => setIsClockedIn(!isClockedIn)} style={{ width: '100%', padding: '18px', backgroundColor: isClockedIn ? '#1e8e3e' : terracotta, borderRadius: '15px', border: 'none', color: '#fff', fontWeight: '900', marginBottom: '25px' }}>
              {isClockedIn ? "ORDER ACTIVE ✅" : "CLOCK IN FOR LUNCH"}
            </button>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ display: 'flex', justifyContent: 'space-between', padding: '18px 0', borderBottom: '1px solid #1a1a1a' }}>
                <span style={{ color: terracotta, fontWeight: '800' }}>{item.day}</span>
                <span style={{ color: '#ccc', textAlign: 'right', flex: 1, marginLeft: '20px' }}>{item.meal}</span>
              </div>
            ))}
          </div>
        )}

        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 20px 20px' }}>
            <h3 style={{ fontSize: '0.85rem', color: terracotta, textTransform: 'uppercase', padding: '20px 0 10px' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', padding: '15px', backgroundColor: '#111', borderRadius: '18px', marginBottom: '12px' }}>
                <div style={{ flex: 1 }}>
                  <h4 style={{ margin: 0, fontWeight: '700' }}>{item.name}</h4>
                  <div style={{ color: gold, fontWeight: 'bold' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', padding: '8px 18px', borderRadius: '20px', fontWeight: '900' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}
      </main>

      {/* 6. FLOATING BAR */}
      {cart.length > 0 && (
        <div onClick={() => setIsCheckoutOpen(true)} style={{ position: 'fixed', bottom: '25px', left: '50%', transform: 'translateX(-50%)', width: '92%', backgroundColor: terracotta, padding: '20px', borderRadius: '20px', display: 'flex', justifyContent: 'space-between', fontWeight: '900', boxShadow: '0 10px 30px rgba(0,0,0,0.5)', cursor: 'pointer', zIndex: 1001 }}>
          <span>{cart.length} ITEMS</span>
          <span>ORDER VIA WHATSAPP ₦{total.toLocaleString()}</span>
        </div>
      )}

      {/* 7. BANK DETAILS MODAL */}
      {isCheckoutOpen && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.95)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#111', borderTopLeftRadius: '30px', borderTopRightRadius: '30px', padding: '30px 20px', boxSizing: 'border-box' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h2 style={{ margin: 0 }}>Transfer Receipt</h2>
              <button onClick={() => setIsCheckoutOpen(false)} style={{ background: 'none', border: 'none', color: '#888', fontSize: '1.5rem' }}>✕</button>
            </div>
            <div style={{ padding: '20px', backgroundColor: '#1a1a1a', borderRadius: '20px', border: `1px solid ${gold}`, marginBottom: '20px' }}>
              <p style={{ color: gold, fontSize: '0.7rem', fontWeight: 'bold', margin: '0 0 5px 0' }}>PREMIUMTRUST BANK:</p>
              <p style={{ margin: '3px 0', fontSize: '1.4rem', fontWeight: '900', color: '#fff' }}>0112326977</p>
              <p style={{ margin: 0, fontSize: '0.8rem', opacity: 0.7 }}>OLUKOYA OMOTOYOSI</p>
            </div>
            <button onClick={sendToWhatsApp} style={{ width: '100%', padding: '20px', backgroundColor: terracotta, color: '#fff', borderRadius: '15px', border: 'none', fontWeight: '900', fontSize: '1rem' }}>
              I'VE PAID, SEND RECEIPT
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
